from flask import Flask, jsonify, request
from pymongo import MongoClient
import json
from bson.json_util import dumps

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)

# Select database and collection
db = client['content_management']
users = db['users']

# User profile storage
@app.route('/user/profile', methods=['GET'])
def get_user_profile():
    user_id = request.args.get('id')
    if user_id:
        user = users.find_one({'_id': int(user_id)})
        return dumps(user)
    else:
        return jsonify({'error': 'User ID not provided'})

# Document queries
@app.route('/documents', methods=['GET'])
def get_documents():
    filter_query = json.loads(request.args.get('query'))
    documents = db['documents'].find(filter_query)
    return dumps(list(documents))

@app.route('/documents/aggregation', methods=['POST'])
def run_aggregation():
    aggregation_pipeline = json.loads(request.get_json().get('pipeline'))
    results = db['documents'].aggregate(aggregation_pipeline)
    return dumps(list(results))

if __name__ == '__main__':
    app.run(debug=True)

# Aggregation example
db['documents'].insert_many([
    {'title': 'Document 1', 'content': 'This is a sample document.'},
    {'title': 'Document 2', 'content': 'Another sample document.'}
])

pipeline = [
    {
        '$match': {
            'title': 'sample'
        }
    },
    {
        '$project': {
            '_id': 0,
            'title': 1
        }
    }
]

print(list(db['documents'].aggregate(pipeline)))